<template>
  <div class="tool-content" style="font-family: -apple-system, BlinkMacSystemFont, 'SF Pro Text', 'PingFang SC', 'Microsoft YaHei', sans-serif">
    <div
      style="background: rgba(23, 162, 184, 0.1); border-left: 3px solid #17a2b8; padding: 12px 15px; border-radius: 8px; margin-bottom: 18px"
    >
      <p style="margin: 0 0 6px 0; color: #a0e6f0; font-size: 13px">
        <i class="fa-solid fa-info-circle" style="margin-right: 6px; color: #17a2b8"></i>
        输入角色描述，AI 自动生成角色卡（YAML 格式，纯中文）。
      </p>
      <p style="margin: 0; color: #93c5fd; font-size: 11px">
        包含：基础信息、外貌、核心性格、对话风格、背景经历、人际关系、演绎指导
      </p>
    </div>

    <!-- 角色描述 -->
    <div style="margin: 15px 0">
      <label :style="labelStyle">角色描述：</label>
      <textarea v-model="characterDescription" placeholder="请描述角色的基本信息，如外观、性格、背景等..." :style="textareaStyle"></textarea>
    </div>

    <!-- 流式开关 -->
    <label style="display: flex; align-items: center; gap: 10px; margin: 15px 0; color: #ccc; font-size: 13px; cursor: pointer">
      <input v-model="enableCharacterStreaming" type="checkbox" style="width: 17px; height: 17px; accent-color: #0a84ff" />
      启用流式传输（可查看生成进度）
    </label>

    <!-- 进度 -->
    <div v-if="(isGeneratingCharacter || isModifyingCharacter) && characterProgressPercent > 0" style="margin: 15px 0">
      <div style="width: 100%; height: 8px; background: rgba(255,255,255,0.1); border-radius: 999px; overflow: hidden">
        <div :style="{ width: characterProgressPercent + '%', height: '100%', background: '#17a2b8', transition: 'width 0.3s' }"></div>
      </div>
      <div style="text-align: center; margin-top: 8px; color: #17a2b8; font-size: 12px; font-weight: 600">
        {{ isModifyingCharacter ? '修改' : '生成' }}中... {{ characterProgressPercent.toFixed(0) }}%
      </div>
    </div>

    <!-- 操作按钮 -->
    <div style="display: flex; gap: 10px; margin-bottom: 20px">
      <button :disabled="isGeneratingCharacter || !characterDescription.trim()" :style="primaryBtn" @click="handleGenerateCharacterCard">
        <i class="fa-solid fa-magic"></i> {{ isGeneratingCharacter ? '生成中...' : '生成角色卡' }}
      </button>
      <button :style="secondaryBtn" @click="clearCharacterForm"><i class="fa-solid fa-trash"></i> 清空</button>
    </div>

    <!-- 输出 -->
    <div v-if="characterCardOutput">
      <h5 style="margin: 0 0 12px 0; color: #f5f5f7; font-size: 14px; font-weight: 600">
        <i class="fa-solid fa-check-circle" style="margin-right: 6px; color: #30d158"></i>生成的角色卡：
      </h5>
      <div :style="outputBox">{{ characterCardOutput }}</div>

      <div style="margin-top: 12px; display: flex; gap: 10px; flex-wrap: wrap">
        <button :style="pillBtn('#0a84ff')" @click="copyCharacterCard"><i class="fa-solid fa-copy"></i> 复制角色卡</button>
        <button :disabled="isGeneratingMvu" :style="pillBtn('rgba(102,126,234,0.2)', '#8ea2f0')" @click="generateMvuFromCharacter">
          <i class="fa-solid fa-flask"></i> {{ isGeneratingMvu ? '生成中...' : '生成配套 MVU 变量' }}
        </button>
      </div>

      <!-- MVU 输出 -->
      <div v-if="mvuVarOutput" style="margin-top: 12px; padding: 14px; background: rgba(102,126,234,0.08); border: 0.5px solid rgba(102,126,234,0.3); border-radius: 12px">
        <h5 style="margin: 0 0 10px 0; color: #8ea2f0; font-size: 13px; font-weight: 600"><i class="fa-solid fa-flask" style="margin-right: 6px"></i>配套 MVU 变量（[InitVar]）</h5>
        <div :style="outputBox" style="font-family: 'Courier New', monospace; max-height: 240px">{{ mvuVarOutput }}</div>
        <button :style="pillBtn('rgba(255,255,255,0.1)', '#f5f5f7')" style="margin-top: 10px" @click="copyToClipboard(mvuVarOutput, 'MVU 变量已复制')">
          <i class="fa-solid fa-copy"></i> 复制变量 JSON
        </button>
        <p style="margin: 8px 0 0 0; color: #888; font-size: 11px">放进名字含 [InitVar] 的世界书条目即可；更多配置见 MVU 标签页</p>
      </div>

      <!-- 插入 -->
      <div style="margin-top: 18px; padding: 14px; background: rgba(23,162,184,0.1); border: 0.5px solid rgba(23,162,184,0.3); border-radius: 12px">
        <h5 style="margin: 0 0 12px 0; color: #17a2b8; font-size: 13px; font-weight: 600"><i class="fa-solid fa-file-import" style="margin-right: 6px"></i>插入生成内容</h5>
        <div style="display: flex; gap: 10px; align-items: center; flex-wrap: wrap; margin-bottom: 10px">
          <select v-model="characterInsertPosition" :style="inputStyle" style="flex: 1; min-width: 200px">
            <option v-for="pos in characterInsertPositions" :key="pos.value" :value="pos.value">{{ pos.label }}</option>
          </select>
          <button :disabled="isInsertingCharacter || (characterInsertPosition === 'worldbook' && !characterInsertWorldbook)" :style="pillBtn('rgba(255,255,255,0.1)', '#f5f5f7')" @click="insertCharacterCard">
            <i class="fa-solid fa-download"></i> {{ isInsertingCharacter ? '插入中...' : '插入' }}
          </button>
        </div>
        <div v-if="characterInsertPosition === 'worldbook'" style="margin-bottom: 10px">
          <select v-model="characterInsertWorldbook" :style="inputStyle">
            <option value="">选择目标世界书...</option>
            <option v-for="wb in availableWorldbooks" :key="wb" :value="wb">{{ wb }}</option>
          </select>
        </div>
        <p style="margin: 0; color: #888; font-size: 11px">
          {{ characterInsertPosition === 'worldbook' ? '将作为新条目插入到所选世界书' : '插入会覆盖所选位置的原有内容' }}
        </p>
      </div>

      <!-- 修改 -->
      <div style="margin-top: 20px; border-top: 1px dashed rgba(255,255,255,0.15); padding-top: 18px">
        <h5 style="margin: 0 0 12px 0; color: #f5f5f7; font-size: 14px; font-weight: 600"><i class="fa-solid fa-edit" style="margin-right: 6px; color: #ffa500"></i>修改角色卡</h5>
        <textarea v-model="modifyRequest" placeholder='描述你想要修改的内容，如"让角色更活泼"、"增加魔法技能"...' :style="textareaStyle" style="min-height: 80px"></textarea>
        <div style="display: flex; gap: 10px; margin-top: 12px">
          <button :disabled="isModifyingCharacter || !modifyRequest.trim()" :style="primaryBtn" @click="handleModifyCharacterCard">
            <i class="fa-solid fa-wand-magic-sparkles"></i> {{ isModifyingCharacter ? '修改中...' : 'AI 修改' }}
          </button>
          <button :style="secondaryBtn" @click="clearModifyRequest"><i class="fa-solid fa-eraser"></i> 清空修改需求</button>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { onMounted, ref, type Ref } from 'vue';
import { storeToRefs } from 'pinia';
import { useSettingsStore } from '../../settings';
import { copyToClipboard } from '../../utils';
import { translateError } from '../../utils/error-handler';
import { requestToolsAiText } from './toolsAiService';
import { CHARACTER_CARD_GENERATE_SYSTEM_PROMPT, CHARACTER_CARD_MODIFY_SYSTEM_PROMPT } from './toolsPrompts';
import { useWorldbook } from './useToolsCommon';

const { settings } = storeToRefs(useSettingsStore());
const { availableWorldbooks, loadAvailableWorldbooks } = useWorldbook();

const characterDescription = ref('');
const characterCardOutput = ref('');
const isGeneratingCharacter = ref(false);
const modifyRequest = ref('');
const isModifyingCharacter = ref(false);
const enableCharacterStreaming = ref(false);
const characterProgressPercent = ref(0);
const characterInsertPosition = ref('description');
const isInsertingCharacter = ref(false);
const isGeneratingMvu = ref(false);
const mvuVarOutput = ref('');
const characterInsertWorldbook = ref('');

const characterInsertPositions = [
  { value: 'description', label: '角色描述 (Description)' },
  { value: 'personality', label: '角色性格 (Personality)' },
  { value: 'scenario', label: '场景 (Scenario)' },
  { value: 'first_mes', label: '首条消息 (First Message)' },
  { value: 'mes_example', label: '示例对话 (Example Messages)' },
  { value: 'system_prompt', label: '系统提示词 (System Prompt)' },
  { value: 'post_history_instructions', label: '后历史指令 (Jailbreak)' },
  { value: 'creator_notes', label: '创作者备注 (Creator Notes)' },
  { value: 'worldbook', label: '世界书条目 (新建)' },
];

// ===== 样式 =====
const labelStyle = 'display: block; margin-bottom: 8px; color: #ccc; font-size: 13px; font-weight: 500;';
const inputStyle =
  'box-sizing: border-box; padding: 10px 12px; background: rgba(255,255,255,0.06); border: 0.5px solid rgba(255,255,255,0.12); border-radius: 12px; color: #f5f5f7; font-size: 13px; font-family: inherit;';
const textareaStyle =
  'width: 100%; box-sizing: border-box; min-height: 120px; padding: 12px; background: rgba(255,255,255,0.06); border: 0.5px solid rgba(255,255,255,0.12); border-radius: 12px; color: #f5f5f7; font-size: 13px; resize: vertical; font-family: inherit; line-height: 1.55;';
const outputBox =
  'background: rgba(0,0,0,0.25); border: 0.5px solid rgba(255,255,255,0.08); border-radius: 12px; padding: 14px; color: #e0e0e0; font-size: 13px; line-height: 1.6; white-space: pre-wrap; word-wrap: break-word; max-height: 300px; overflow-y: auto;';
const primaryBtn =
  'padding: 11px 20px; background: #0a84ff; border: none; border-radius: 11px; color: #fff; font-size: 13px; font-weight: 600; cursor: pointer; display: inline-flex; align-items: center; gap: 6px;';
const secondaryBtn =
  'padding: 11px 20px; background: rgba(255,255,255,0.1); border: none; border-radius: 11px; color: #f5f5f7; font-size: 13px; font-weight: 500; cursor: pointer; display: inline-flex; align-items: center; gap: 6px;';
function pillBtn(bg: string, color = '#fff'): string {
  return `padding: 9px 16px; background: ${bg}; border: none; border-radius: 999px; color: ${color}; font-size: 12.5px; font-weight: 600; cursor: pointer; display: inline-flex; align-items: center; gap: 6px;`;
}

const requestAiText = (requestPayload: Record<string, any>, progressRef?: Ref<number>) =>
  requestToolsAiText({ requestPayload, settings: settings.value as any, progressRef });

const cleanCharacterCardOutput = (text: string): string => {
  let cleaned = text;
  const prefixPatterns = [
    /^.*?(?:好的|当然|没问题|以下是|我将|我来|让我)[^]*?(?:角色|创造|设计|生成)[^]*?[:：。\n]/i,
    /^.*?(?:根据你的要求|按照你的描述)[^]*?[:：。\n]/i,
    /^[^]*?---\s*\n/,
  ];
  for (const pattern of prefixPatterns) cleaned = cleaned.replace(pattern, '');
  cleaned = cleaned.replace(/^```(?:yaml|yml|json|markdown|md)?\s*\n?/gim, '');
  cleaned = cleaned.replace(/\n?```\s*$/gim, '');
  cleaned = cleaned.replace(/```/g, '');
  cleaned = cleaned.replace(/^\s*\n+/, '').replace(/\n+\s*$/, '');
  return cleaned.trim();
};

const handleGenerateCharacterCard = async () => {
  if (!characterDescription.value.trim()) {
    window.toastr.warning('请输入角色描述');
    return;
  }
  try {
    isGeneratingCharacter.value = true;
    characterProgressPercent.value = 0;
    window.toastr.info('AI正在生成角色卡，请稍候...');
    const requestPayload = {
      model: settings.value.model || 'gpt-3.5-turbo',
      max_tokens: settings.value.max_tokens || 16000,
      temperature: 0.8,
      stream: enableCharacterStreaming.value,
      messages: [
        { role: 'system', content: CHARACTER_CARD_GENERATE_SYSTEM_PROMPT },
        { role: 'user', content: characterDescription.value },
      ],
    };
    const generatedText = await requestAiText(requestPayload, characterProgressPercent);
    characterCardOutput.value = cleanCharacterCardOutput(generatedText);
    window.toastr.success('角色卡生成完成！');
  } catch (error) {
    console.error('角色卡生成失败:', error);
    window.toastr.error(translateError(error, '生成'));
  } finally {
    isGeneratingCharacter.value = false;
    characterProgressPercent.value = 0;
  }
};

const handleModifyCharacterCard = async () => {
  if (!modifyRequest.value.trim()) {
    window.toastr.warning('请输入修改需求');
    return;
  }
  if (!characterCardOutput.value) {
    window.toastr.warning('没有可修改的角色卡，请先生成角色卡');
    return;
  }
  try {
    isModifyingCharacter.value = true;
    characterProgressPercent.value = 0;
    window.toastr.info('AI正在根据你的需求修改角色卡，请稍候...');
    const requestPayload = {
      model: settings.value.model || 'gpt-3.5-turbo',
      max_tokens: settings.value.max_tokens || 16000,
      temperature: 0.8,
      stream: enableCharacterStreaming.value,
      messages: [
        { role: 'system', content: CHARACTER_CARD_MODIFY_SYSTEM_PROMPT },
        {
          role: 'user',
          content: `以下是现有的角色卡：\n\n${characterCardOutput.value}\n\n---\n\n请根据以下修改需求调整角色卡：\n${modifyRequest.value}`,
        },
      ],
    };
    const modifiedCard = await requestAiText(requestPayload, characterProgressPercent);
    characterCardOutput.value = cleanCharacterCardOutput(modifiedCard);
    modifyRequest.value = '';
    window.toastr.success('角色卡修改完成！');
  } catch (error) {
    console.error('角色卡修改失败:', error);
    window.toastr.error(translateError(error, '修改'));
  } finally {
    isModifyingCharacter.value = false;
    characterProgressPercent.value = 0;
  }
};

const clearCharacterForm = () => {
  characterDescription.value = '';
  characterCardOutput.value = '';
  modifyRequest.value = '';
  window.toastr.success('内容已清空');
};

const clearModifyRequest = () => {
  modifyRequest.value = '';
  window.toastr.success('修改需求已清空');
};

const copyCharacterCard = () => {
  if (!characterCardOutput.value) {
    window.toastr.warning('没有可复制的内容');
    return;
  }
  copyToClipboard(characterCardOutput.value, '角色卡已复制到剪贴板');
};

const generateMvuFromCharacter = async () => {
  if (!characterCardOutput.value) {
    window.toastr.warning('请先生成角色卡');
    return;
  }
  if (isGeneratingMvu.value) return;
  isGeneratingMvu.value = true;
  try {
    const systemPrompt = `你是 MVU（MagVarUpdate）变量系统设计专家。请根据给定的角色卡，设计一套贴合该角色的 MVU 变量结构，用于追踪角色属性、状态、关系、剧情进度等。

# 输出格式（严格遵守）
- 只输出一个 JSON 对象，不要任何解释或代码块标记。
- 顶层是 $meta 和一个变量根节点（用角色名或"角色"作为根 key），不要包含 stat_data 根节点。
- 每个变量是 [初始值, "更新条件/说明"] 的二元数组（ValueWithDescription）。
- $meta 默认 { "extensible": false }（结构锁定）。
- 需要让 AI 增删元素的数组，在数组里放入魔法字符串 "$__META_EXTENSIBLE__$"。
- 需要让 AI 增删键的对象，在对象里加 "$meta": { "extensible": true }。
- 描述精炼（15-20字），说明取值范围与更新时机。`;
    const requestPayload = {
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: `角色卡内容：\n\n${characterCardOutput.value}` },
      ],
    };
    const generatedText = await requestAiText(requestPayload);
    let jsonText = (generatedText || '').replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();
    const match = jsonText.match(/\{[\s\S]*\}/);
    if (match) jsonText = match[0];
    try {
      JSON.parse(jsonText);
      mvuVarOutput.value = jsonText;
    } catch {
      mvuVarOutput.value = jsonText;
      window.toastr.warning('生成的 JSON 可能需要手动微调');
    }
    window.toastr.success('配套 MVU 变量已生成');
  } catch (error) {
    console.error('生成 MVU 变量失败:', error);
    window.toastr.error(translateError(error, '生成'));
  } finally {
    isGeneratingMvu.value = false;
  }
};

const insertCharacterCard = async () => {
  if (!characterCardOutput.value) {
    window.toastr.warning('没有可插入的内容');
    return;
  }
  try {
    isInsertingCharacter.value = true;
    const position = characterInsertPosition.value;
    const positionLabel = characterInsertPositions.find(p => p.value === position)?.label || position;
    const tav = (window as any).TavernHelper;

    if (position === 'worldbook') {
      if (!characterInsertWorldbook.value) {
        window.toastr.warning('请先选择目标世界书');
        return;
      }
      window.toastr.info(`正在插入到世界书「${characterInsertWorldbook.value}」...`);
      if (!tav?.createWorldbookEntries) throw new Error('TavernHelper.createWorldbookEntries 不可用');
      const newEntry = {
        content: characterCardOutput.value,
        comment: '角色卡生成 - ' + new Date().toLocaleString(),
        keys: ['角色设定'],
        enabled: true,
      };
      await tav.createWorldbookEntries(characterInsertWorldbook.value, [newEntry], { render: 'immediate' });
      window.toastr.success(`已插入到世界书「${characterInsertWorldbook.value}」`);
      return;
    }

    window.toastr.info(`正在插入到「${positionLabel}」...`);
    const st = (window as any).SillyTavern || (window as any).parent?.SillyTavern;

    if (tav?.setCharData) {
      await tav.setCharData('current', { [position]: characterCardOutput.value });
      window.toastr.success(`已插入到「${positionLabel}」`);
      return;
    }

    if (st?.getContext) {
      const ctx = st.getContext();
      const charId = ctx.characterId ?? ctx.characters?.findIndex?.((c: any) => c.avatar === ctx.character?.avatar);
      if (charId === undefined || charId < 0) throw new Error('未找到当前角色');
      const updateData: any = {};
      if (['system_prompt', 'post_history_instructions', 'creator_notes'].includes(position)) {
        updateData[`data.${position}`] = characterCardOutput.value;
      } else {
        updateData[position] = characterCardOutput.value;
      }
      const response = await fetch('/api/characters/edit', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ avatar_url: ctx.characters?.[charId]?.avatar, ...updateData }),
      });
      if (response.ok) {
        window.toastr.success(`已插入到「${positionLabel}」，请刷新页面查看`);
        return;
      }
    }

    const fieldMap: Record<string, string> = {
      description: '#description_textarea, textarea[name="description"]',
      personality: '#personality_textarea, textarea[name="personality"]',
      scenario: '#scenario_textarea, textarea[name="scenario"]',
      first_mes: '#firstmessage_textarea, textarea[name="first_mes"]',
      mes_example: '#mes_example_textarea, textarea[name="mes_example"]',
      system_prompt: '#character_system_prompt, textarea[name="system_prompt"]',
      post_history_instructions: '#character_jailbreak, textarea[name="post_history_instructions"]',
      creator_notes: '#creator_notes_textarea, textarea[name="creator_notes"]',
    };
    const selector = fieldMap[position];
    if (selector) {
      const parentDoc = window.parent?.document || document;
      const textarea = parentDoc.querySelector(selector) as HTMLTextAreaElement;
      if (textarea) {
        textarea.value = characterCardOutput.value;
        textarea.dispatchEvent(new Event('input', { bubbles: true }));
        textarea.dispatchEvent(new Event('change', { bubbles: true }));
        window.toastr.success(`已插入到「${positionLabel}」，记得保存角色卡！`);
        return;
      }
    }

    window.toastr.warning('无法自动插入，已复制到剪贴板，请手动粘贴');
    copyToClipboard(characterCardOutput.value);
  } catch (error) {
    console.error('插入角色卡失败:', error);
    window.toastr.error('插入失败: ' + (error as Error).message);
  } finally {
    isInsertingCharacter.value = false;
  }
};

onMounted(loadAvailableWorldbooks);
</script>
